  ('locality-6f0ba476-moex-00463', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-d3ff7f6b', 'sub-locality-6f0ba476-06', NULL, 'single_choice', '令橫軸變數為實質GDP，縱軸變數為一般物價水準。根據IS-LM與AD-AS模型，當邊際消費傾 向愈高且投資對利率愈敏感時，在其他條件不變下：', '["AD線愈陡", "AD線愈平坦", "AD線的斜度不受影響", "AD線的斜度因題幹說明不足，無法判斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
